 1	import React, { FC } from 'react';
 2	import { useNMStateTranslation } from 'src/utils/hooks/useNMStateTranslation';
 3	
 4	import { Button, FormGroup, GridItem, TextInput, Tooltip } from '@patternfly/react-core';
 5	import { MinusCircleIcon } from '@patternfly/react-icons';
 6	
 7	import { IDLabel } from '../utils/types';
 8	
 9	type LabelRowProps = {
10	  label: IDLabel;
11	  onChange: (label: IDLabel) => void;
12	  onDelete: (id: number) => void;
13	};
14	
15	const LabelRow: FC<LabelRowProps> = ({ label, onChange, onDelete }) => {
16	  const { t } = useNMStateTranslation();
17	  const { id, key, value } = label;
18	  return (
19	    <>
20	      <GridItem span={6}>
21	        <FormGroup label={t('Key')} fieldId={`label-${id}-key-input`}>
22	          <TextInput
23	            id={`label-${id}-key-input`}
24	            placeholder={t('Key')}
25	            isRequired
26	            type="text"
27	            value={key}
28	            onChange={(_, newKey) => onChange({ ...label, key: newKey })}
29	            aria-label={t('selector key')}
30	          />
31	        </FormGroup>
32	      </GridItem>
33	      <GridItem span={5}>
34	        <FormGroup label={t('Value')} fieldId={`label-${id}-value-input`}>
35	          <TextInput
36	            id={`label-${id}-value-input`}
37	            placeholder={t('Value')}
38	            isRequired
39	            type="text"
40	            value={value}
41	            onChange={(_, newValue) => onChange({ ...label, value: newValue })}
42	            aria-label={t('selector value')}
43	          />
44	        </FormGroup>
45	      </GridItem>
46	
47	      <GridItem span={1}>
48	        <FormGroup label=" " fieldId={`label-${id}-delete-btn`}>
49	          <Tooltip content={t('Remove label selector')}>
50	            <Button variant="plain" onClick={() => onDelete(id)}>
51	              <MinusCircleIcon />
52	            </Button>
53	          </Tooltip>
54	        </FormGroup>
55	      </GridItem>
56	    </>
57	  );
58	};
59	
60	export default LabelRow;

